import{_ as o,o as a,c as t,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"64. Compassionate Leave","description":"","frontmatter":{"title":"64. Compassionate Leave","eba":"Doctors in Training 2022-2026","topics":["leave","compassionate-leave","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/leave/64-compassionate-leave.md","filePath":"ebas/doctors-in-training/leave/64-compassionate-leave.md"}'),r={name:"ebas/doctors-in-training/leave/64-compassionate-leave.md"};function i(n,e,p,l,c,m){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="_64-compassionate-leave" tabindex="-1">64. Compassionate Leave <a class="header-anchor" href="#_64-compassionate-leave" aria-label="Permalink to &quot;64. Compassionate Leave&quot;">​</a></h1><p><strong>64.1</strong> Amount of Compassionate Leave</p><p><strong>(a)</strong> Doctors are entitled to two days’ compassionate leave on each occasion (a permissible occasion) when;</p><p><strong>(i)</strong> a member of the Doctor&#39;s immediate family or a member of the Doctor&#39;s household:</p><p>A. contracts or develops a personal illness that poses a serious threat to his or her life;</p><p>B. sustains a personal injury that poses a serious threat to his/her life; or</p><p>C. dies; or</p><p><strong>(ii)</strong> a Stillborn Child is born, where the Stillborn Child would have been a member of the Doctor’s immediate family, or a member of the Doctor’s household, if the Stillborn Child had been born alive; or</p><p><strong>(iii)</strong> a Doctor, or a Doctor’s spouse or de facto partner, has a miscarriage. This sub-clause 64.1(a)(ii) does not apply if the miscarriage results in a Stillborn Child.</p><p><strong>(b)</strong> If the permissible occasion is the contraction or development of a personal illness, or the sustaining of a personal injury, the Doctor may take the compassionate leave for that occasion at any time while the illness or injury persists.</p><p><strong>64.2</strong> Payment Calculation</p><p>The compassionate leave must be paid for a particular permissible occasion according to the roster or projected roster, not including overtime or penalty rates.</p><p><strong>64.3</strong> Taking of Leave</p><p><strong>(a)</strong> The Doctor must provide proof of death or illness to the satisfaction of the Health Service.</p><p><strong>(b)</strong> Any unused portion of compassionate leave will not accrue from year to year and will not be paid out on termination.</p><p><strong>(c)</strong> Such leave does not have to be taken consecutively.</p><p><strong>(d)</strong> A Doctor may take unpaid compassionate leave by agreement with the Health Service.</p><p><strong>(e)</strong> The Health Service will require the Doctor to provide satisfactory evidence to support the taking of compassionate leave.</p><p>Plain language terms: bereavement leave.</p>',19)])])}const g=o(r,[["render",i]]);export{d as __pageData,g as default};
